  "steps": [
    {
      "order": 1,
      "title": "봄동 손질하기",
      "description": [
        {
          "content": "봄동 한 포기(260g)를 준비합니다.",
          "start": "00:00:32",
          "end": "00:00:36"
        },
        {
          "content": "봄동을 엎어서 반으로 나눕니다.",
          "start": "00:00:36",
          "end": "00:00:40"
        },
        {
          "content": "나눈 봄동을 다시 한 번 반으로 나눕니다.",
          "start": "00:00:40",
          "end": "00:00:43"
        }
      ],
      "timerSeconds": null,
      "scenes": [
        {
          "start": "00:00:36",
          "end": "00:00:40",
          "label": "봄동 반으로 나누기"
        },
        {
          "start": "00:00:40",
          "end": "00:00:43",
          "label": "다시 반으로 나누기"
        }
      ]
    },
    {
      "order": 2,
      "title": "봄동 다듬기",
      "description": [
        {
          "content": "봄동의 뿌리 부분을 잘라냅니다.",
          "start": "00:00:43",
          "end": "00:00:49"
        },
        {
          "content": "똑같은 방법으로 나머지 봄동의 뿌리도 잘라줍니다.",
          "start": "00:00:49",
          "end": "00:00:53"
        },
        {
          "content": "잎이 굵은 것은 반으로 나누어 줍니다.",
          "start": "00:00:53",
          "end": "00:00:58"
        }
      ],
      "timerSeconds": null,
      "scenes": [
        {
          "start": "00:00:43",
          "end": "00:00:49",
          "label": "뿌리 부분 잘라내기"
        },
        {
          "start": "00:00:53",
          "end": "00:00:58",
          "label": "굵은 잎 나누기"
        }
      ]
    },
    {
      "order": 3,
      "title": "봄동 씻기",
      "description": [
        {
          "content": "대야에 미지근한 물을 받습니다.",
          "start": "00:00:58",
          "end": "00:01:05"
        },
        {
          "content": "손질한 봄동을 물에 넣습니다.",
          "start": "00:01:05",
          "end": "00:01:08"
        },
        {
          "content": "봄동을 찰랑찰랑 흔들어가며 첫 번째로 씻어줍니다.",
          "start": "00:01:08",
          "end": "00:01:21"
        },
        {
          "content": "물을 갈아준 뒤 두 번째로 봄동을 씻어줍니다.",
          "start": "00:01:21",
          "end": "00:01:36"
        }
      ],
      "timerSeconds": null,
      "scenes": [
        {
          "start": "00:01:08",
          "end": "00:01:21",
          "label": "흔들어가며 씻기"
        }
      ]
    },
    {
      "order": 4,
      "title": "봄동 헹구기",
      "description": [
        {
          "content": "마지막 세 번째로 봄동을 꼼꼼히 씻어줍니다.",
          "start": "00:01:36",
          "end": "00:01:45"
        },
        {
          "content": "흐르는 물에 봄동을 가볍게 샤워시켜 헹굽니다.",
          "start": "00:01:45",
          "end": "00:01:49"
        }
      ],
      "timerSeconds": null,
      "scenes": [
        {
          "start": "00:01:45",
          "end": "00:01:49",
          "label": "흐르는 물에 헹구기"
        }
      ]
    },
    {
      "order": 5,
      "title": "양념할 봄동 준비하기",
      "description": [
        {
          "content": "커다란 스테인리스 양념 볼을 준비합니다.",
          "start": "00:01:49",
          "end": "00:01:53"
        },
        {
          "content": "씻어둔 봄동의 물기를 탈탈 털어서 볼에 담습니다.",
          "start": "00:01:53",
          "end": "00:02:02"
        }
      ],
      "timerSeconds": null,
      "scenes": [
        {
          "start": "00:01:53",
          "end": "00:02:02",
          "label": "물기 털어 담기"
        }
      ]
    },
    {
      "order": 6,
      "title": "기본 양념 넣기",
      "description": [
        {
          "content": "고춧가루 3스푼을 넣습니다.",
          "start": "00:02:02",
          "end": "00:02:10"
        },
        {
          "content": "다진 마늘 1스푼을 추가합니다.",
          "start": "00:02:10",
          "end": "00:02:16"
        },
        {
          "content": "까나리액젓 1스푼을 넣습니다.",
          "start": "00:02:16",
          "end": "00:02:19"
        },
        {
          "content": "진간장 2스푼을 넣습니다.",
          "start": "00:02:19",
          "end": "00:02:22"
        }
      ],
      "timerSeconds": null,
      "scenes": []
    },
    {
      "order": 7,
      "title": "단맛과 윤기 더하기",
      "description": [
        {
          "content": "매실청 1스푼을 넣습니다.",
          "start": "00:02:22",
          "end": "00:02:27"
        },
        {
          "content": "윤기를 위해 물엿 1/2스푼을 넣습니다.",
          "start": "00:02:27",
          "end": "00:02:32"
        }
      ],
      "timerSeconds": null,
      "scenes": []
    },
    {
      "order": 8,
      "title": "봄동겉절이 버무려 완성하기",
      "description": [
        {
          "content": "양념이 잘 섞이도록 봄동을 살금살금 버무립니다.",
          "start": "00:02:32",
          "end": "00:02:36"
        },
        {
          "content": "통깨 1스푼을 골고루 뿌려줍니다.",
          "start": "00:02:36",
          "end": "00:02:40"
        },
        {
          "content": "가볍게 한 번 더 섞어 봄동겉절이를 완성합니다.",
          "start": "00:02:40",
          "end": "00:02:50"
        }
      ],
      "timerSeconds": null,
      "scenes": [
        {
          "start": "00:02:32",
          "end": "00:02:36",
          "label": "살금살금 버무리기"
        }
      ]
    },
    {
      "order": 9,
      "title": "달걀 프라이 만들기",
      "description": [
        {
          "content": "팬에 달걀 1개를 깨서 넣습니다.",
          "start": "00:02:50",
          "end": "00:02:54"
        },
        {
          "content": "소금을 살짝 뿌려 달걀 프라이를 만듭니다.",
          "start": "00:02:54",
          "end": "00:03:03"
        }
      ],
      "timerSeconds": null,
      "scenes": []
    },
    {
      "order": 10,
      "title": "비빔밥 재료 올리기",
      "description": [
        {
          "content": "완성된 봄동겉절이에 밥을 적당량 넣습니다.",
          "start": "00:03:03",
          "end": "00:03:09"
        },
        {
          "content": "밥 위에 미리 만든 달걀 프라이를 올립니다.",
          "start": "00:03:09",
          "end": "00:03:14"
        }
      ],
      "timerSeconds": null,
      "scenes": []
    },
    {
      "order": 11,
      "title": "참기름과 통깨로 마무리하기",
      "description": [
        {
          "content": "참기름을 두 바퀴 정도 둘러줍니다.",
          "start": "00:03:14",
          "end": "00:03:17"
        },
        {
          "content": "통깨를 밥 위에 살짝 뿌립니다.",
          "start": "00:03:17",
          "end": "00:03:22"
        },
        {
          "content": "통깨를 손바닥으로 비벼서 고소한 향이 나게 더 뿌려줍니다.",
          "start": "00:03:22",
          "end": "00:03:31"
        }
      ],
      "timerSeconds": null,
      "scenes": [
        {
          "start": "00:03:14",
          "end": "00:03:17",
          "label": "참기름 두르기"
        },
        {
          "start": "00:03:22",
          "end": "00:03:31",
          "label": "통깨 비벼 뿌리기"
        }
      ]
    },
    {
      "order": 12,
      "title": "봄동 비빔밥 비벼 먹기",
      "description": [
        {
          "content": "완성된 봄동 비빔밥의 모습을 보여줍니다.",
          "start": "00:03:31",
          "end": "00:03:50"
        },
        {
          "content": "비빔밥 재료들을 골고루 잘 섞어줍니다.",
          "start": "00:03:50",
          "end": "00:03:53"
        },
        {
          "content": "완성된 비빔밥을 맛있게 한 입 뜨며 마무리합니다.",
          "start": "00:03:53",
          "end": "00:04:13"
        }
      ],
      "timerSeconds": null,
      "scenes": []
    }
  ],
  "servingTip": "참기름을 두르고 깨를 손으로 비벼서 고소한 향을 더해 드세요."
}
